class Solution(object):
    def maximumLengthSubstring(self, s):
        from collections import defaultdict
        cnt = defaultdict(int)
        left = 0
        best = 0
        for right, c in enumerate(s):
            cnt[c] += 1
            while cnt[c] > 2:
                cnt[s[left]] -= 1
                left += 1
            best = max(best, right - left + 1)
        return best
